const body = $input.first().json.body || {};
const query = String(body.query || body.message || '').trim();
if (!query) {
  return [{ json: { ok: false, error: 'Missing query', status: 400 } }];
}
const q = query.toLowerCase();
let cypher = '';
let queryType = 'generic';
let target = null;
if (q.includes('log4shell') || q.includes('cve-2021-44228')) {
  queryType = 'impact';
  target = 'CVE-2021-44228';
  cypher = `MATCH path = (cve:CVE {id: 'CVE-2021-44228'})<-[:HAS_VULNERABILITY]-(lib:Library)<-[:DEPENDS_ON*1..5]-(svc:Microservice) RETURN svc.name AS service, svc.pci_scope AS pci_scope, svc.exposed AS exposed, length(path) AS dependency_depth, [node IN nodes(path) | node.name] AS chain, cve.cvss AS cvss_score, cve.name AS cve_name ORDER BY dependency_depth`;
} else if (q.includes('spring4shell') || q.includes('cve-2022-22965')) {
  queryType = 'impact';
  target = 'CVE-2022-22965';
  cypher = `MATCH path = (cve:CVE {id: 'CVE-2022-22965'})<-[:HAS_VULNERABILITY]-(lib:Library)<-[:DEPENDS_ON*1..5]-(svc:Microservice) RETURN svc.name AS service, svc.pci_scope AS pci_scope, svc.exposed AS exposed, length(path) AS dependency_depth, [node IN nodes(path) | node.name] AS chain, cve.cvss AS cvss_score, cve.name AS cve_name ORDER BY dependency_depth`;
} else if ((q.includes('server') || q.includes('host')) && q.includes('payment')) {
  queryType = 'hosting';
  target = 'payment-service';
  cypher = `MATCH (svc:Microservice)-[:HOSTED_ON]->(srv:Server) WHERE toLower(svc.name) CONTAINS 'payment' RETURN svc.name AS service, srv.name AS server, srv.ip AS server_ip ORDER BY svc.name`;
} else if (q.includes('dependency chain') && q.includes('user-portal')) {
  queryType = 'dependency_chain';
  target = 'user-portal';
  cypher = `MATCH path = (:Microservice {name: 'user-portal'})-[:DEPENDS_ON*1..5]->(n) RETURN [node IN nodes(path) | coalesce(node.name, node.id)] AS chain, length(path) AS hops ORDER BY hops DESC`;
} else if (q.includes('list all servers')) {
  queryType = 'list_servers';
  cypher = `MATCH (s:Server) RETURN s.name AS server, s.ip AS ip, s.os AS os, s.tier AS tier ORDER BY s.name`;
} else {
  queryType = 'fallback';
  cypher = `MATCH (s:Server)<-[:HOSTED_ON]-(svc:Microservice) RETURN svc.name AS service, s.name AS server ORDER BY server, service`;
}
return [{ json: { ok: true, original_query: query, query_type: queryType, target, cypher } }];

const original = $('Prepare Query').first().json;
const resp = $input.first().json;
const errors = resp.errors || [];
if (errors.length > 0) {
  return [{ json: { success: false, error: errors[0].message, original_query: original.original_query, cypher: original.cypher } }];
}
const result = (resp.results || [])[0] || { columns: [], data: [] };
const rows = (result.data || []).map(r => {
  const obj = {};
  result.columns.forEach((c, i) => obj[c] = r.row[i]);
  return obj;
});
const out = { success: true, original_query: original.original_query, query_type: original.query_type, target: original.target, cypher: original.cypher, row_count: rows.length, rows };
if (original.query_type === 'impact') {
  const affected = rows.map(r => r.service).filter(Boolean);
  const maxCvss = rows.reduce((m, r) => Math.max(m, Number(r.cvss_score || 0)), 0);
  const hasPci = rows.some(r => !!r.pci_scope);
  const hasExposed = rows.some(r => !!r.exposed);
  let risk = 'INFO';
  if (maxCvss >= 9 && (hasPci || hasExposed)) risk = 'CRITICAL';
  else if (maxCvss >= 7 || affected.length >= 3) risk = 'HIGH';
  else if (maxCvss >= 4) risk = 'MEDIUM';
  else if (affected.length > 0) risk = 'LOW';
  const recommended = affected.includes('payment-service') ? 'isolate payment-service' : (affected[0] ? `review ${affected[0]}` : 'no action');
  out.risk_level = risk;
  out.affected_services = affected;
  out.awaiting_confirmation = risk === 'CRITICAL' && affected.includes('payment-service');
  out.recommendation = recommended;
  out.message = affected.length
    ? `${risk}: ${affected.length} affected service(s): ${affected.join(', ')}. Recommended action: ${recommended}.` + (out.awaiting_confirmation ? ' Type confirm isolate payment-service to execute remediation.' : '')
    : `INFO: no affected services found for ${original.target}.`;
} else if (original.query_type === 'hosting') {
  out.risk_level = 'INFO';
  out.awaiting_confirmation = false;
  out.message = rows.length ? `Found ${rows.length} payment-related service hosting record(s).` : 'No payment-related hosting records found.';
} else if (original.query_type === 'dependency_chain') {
  out.risk_level = 'INFO';
  out.awaiting_confirmation = false;
  out.message = rows.length ? `Found ${rows.length} dependency chain(s) for ${original.target}.` : `No dependency chain found for ${original.target}.`;
} else if (original.query_type === 'list_servers') {
  out.risk_level = 'INFO';
  out.awaiting_confirmation = false;
  out.message = `Listed ${rows.length} server(s).`;
} else {
  out.risk_level = 'INFO';
  out.awaiting_confirmation = false;
  out.message = `Returned ${rows.length} row(s).`;
}
return [{ json: out }];
